 import sailpoint.tools.Util;

 String logPrefix = "CNC_RME_Bulk_Request_Config_Rule:";

Map results = new HashMap();

 public void log(String message) {    
   log.error(logPrefix+" "+message);
 }


 log("loggedInUser "+loggedInUser);






 Identity impersonatorIdentity = context.getObjectByName(Identity.class, loggedInUser);
 if (impersonatorIdentity == null) {
   log.error("Cannot find identity: " + loggedInUser);
   return resutls;
 }


 Identity wg = context.getObjectByName(Identity.class,"LDAP Application Admin");

 results.put("isRoleAdmin",impersonatorIdentity.isInWorkGroup(wg));

 log.error("config results "+results);
 return results;
